/* ── HIGH FIDELITY CYBER-MAGIC RED GLITCH PARTICLES ── */
function Particles({ count = 80 }) {
  const ref = useRef(null);
  useEffect(() => {
    const c = ref.current; if (!c) return;
    const ctx = c.getContext("2d");
    let w = c.width = window.innerWidth, h = c.height = window.innerHeight;
    
    // Create dual-type glitch particles: Red Ticks & Twinkling Rose-Crimson Stars
    const pts = Array.from({ length: count }, () => {
      const isTick = Math.random() > 0.45;
      return {
        isTick,
        x: Math.random() * w,
        y: Math.random() * h,
        r: isTick ? Math.random() * 2.5 + 2 : Math.random() * 2.2 + 1.2,
        w: isTick ? Math.random() * 5 + 2.5 : 0, // width for sprinkles
        vx: (Math.random() - 0.5) * 0.45,       // gentle drift
        vy: Math.random() * 0.75 + 0.35,        // slow falling
        a: Math.random() * 0.55 + 0.35,         // opacity
        glitchTimer: Math.random() * 120,
        color: isTick 
          ? `rgba(${Math.floor(Math.random()*30 + 225)}, ${Math.floor(Math.random()*10)}, ${Math.floor(Math.random()*10)}, ${Math.random()*0.65 + 0.35})`
          : `rgba(255, ${Math.floor(Math.random()*40 + 20)}, ${Math.floor(Math.random()*40 + 20)}, ${Math.random()*0.75 + 0.35})`
      };
    });
    
    let raf;
    const draw = () => {
      ctx.clearRect(0, 0, w, h);
      pts.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        p.glitchTimer--;
        
        // Random digital glitch offset (sprinkles jump left/right occasionally)
        let glitchX = 0;
        if (p.isTick && p.glitchTimer <= 0) {
          if (Math.random() > 0.94) {
            glitchX = (Math.random() - 0.5) * 14; // dynamic glitch jump
          }
          if (p.glitchTimer < -4) {
            p.glitchTimer = Math.random() * 130 + 40; // reset glitch timer
          }
        }

        if (p.x < -20) p.x = w + 20;
        if (p.x > w + 20) p.x = -20;
        if (p.y > h + 20) {
          p.y = -20;
          p.x = Math.random() * w;
        }
        
        ctx.save();
        ctx.translate(p.x + glitchX, p.y);
        
        if (p.isTick) {
          // Draw a cyber-magic red glitch sprinkle tick
          ctx.fillStyle = p.color;
          ctx.fillRect(-p.w / 2, -p.r / 2, p.w, p.r);
        } else {
          // Draw 4-point magical glowing red star
          ctx.beginPath();
          for (let i = 0; i < 4; i++) {
            ctx.rotate(Math.PI / 2);
            ctx.lineTo(p.r * 0.35, 0);
            ctx.lineTo(0, p.r);
          }
          ctx.closePath();
          ctx.fillStyle = p.color;
          ctx.fill();
        }
        
        ctx.restore();
      });
      raf = requestAnimationFrame(draw);
    };
    draw();
    const onR = () => { w = c.width = window.innerWidth; h = c.height = window.innerHeight; };
    window.addEventListener("resize", onR);


  return () => { cancelAnimationFrame(raf); window.removeEventListener("resize", onR); };
  }, []);
  return <canvas ref={ref} style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0 }} />;
}

